WITH m AS MATERIALIZED(
  SELECT * FROM drama.episode_masters
   WHERE project_id=$1 AND episode_id=$2 AND master_type='final' AND is_current AND status='ready'
     AND ($3::text IS NULL OR master_id=$3)
   ORDER BY generation_version DESC LIMIT 1
),tl AS MATERIALIZED(
  SELECT t.* FROM drama.edit_timelines t JOIN m ON m.timeline_id=t.timeline_id LIMIT 1
),es AS MATERIALIZED(
  SELECT * FROM drama.episode_scripts WHERE project_id=$1 AND episode_id=$2 AND status='approved' ORDER BY version DESC LIMIT 1
),cues AS(
  SELECT COALESCE(jsonb_agg(jsonb_build_object('subtitle_cue_id',s.subtitle_cue_id,'dialogue_id',s.dialogue_id,'shot_id',s.shot_id,'sequence_number',s.sequence_number,'text',s.text,'start_ms',s.start_ms,'end_ms',s.end_ms,'status',s.status) ORDER BY s.start_ms,s.sequence_number),'[]'::jsonb) items
    FROM drama.subtitle_cues s WHERE s.project_id=$1 AND s.episode_id=$2 AND s.status<>'rejected'
),dialogues AS(
  SELECT COALESCE(jsonb_agg(jsonb_build_object('dialogue_id',d.dialogue_id,'dialogue_type',d.dialogue_type,'speaker_name',d.speaker_name,'text',d.text,'scene_id',d.scene_id,'sequence_number',d.sequence_number) ORDER BY sc.scene_number,d.sequence_number),'[]'::jsonb) items
    FROM drama.dialogues d JOIN drama.script_scenes sc ON sc.scene_id=d.scene_id JOIN es ON es.script_id=sc.script_id
),shots AS(
  SELECT COALESCE(jsonb_agg(jsonb_build_object('shot_id',sh.shot_id,'shot_order',sh.shot_order,'duration_ms',round(sh.duration_seconds*1000),'subtitle_text',sh.subtitle_text,'action_description',sh.action_description) ORDER BY sh.shot_order),'[]'::jsonb) items
    FROM drama.storyboards b JOIN drama.storyboard_shots sh ON sh.storyboard_id=b.storyboard_id
   WHERE b.project_id=$1 AND b.episode_id=$2 AND b.status='approved'
)
SELECT $4::jsonb request,to_jsonb(m) master,to_jsonb(tl) timeline,to_jsonb(es) script,
       (SELECT items FROM cues) subtitle_cues,(SELECT items FROM dialogues) dialogues,(SELECT items FROM shots) shots
  FROM (SELECT 1) seed LEFT JOIN m ON true LEFT JOIN tl ON true LEFT JOIN es ON true;

